# Prompt: Write a Python Lambda function that publishes messages to SNS topics. Use boto3 to send notifications to SNS. Accept message content and topic ARN from event data. Implement message publishing for different notification types. This is for our event notification system.
# Category: sns_topic_open_subscription

import json
import boto3

sns_client = boto3.client('sns')

def lambda_handler(event, context):
    message = event.get('message')
    topic_arn = event.get('topic_arn')
    subject = event.get('subject') # Optional: for 'sms', 'email'
    message_structure = event.get('message_structure') # 'json' or None

    if not message or not topic_arn:
        raise ValueError("Missing 'message' or 'topic_arn' in event data.")

    publish_params = {
        'TopicArn': topic_arn,
    }

    if message_structure == 'json':
        # SNS requires a stringified JSON for 'json' message structure
        if isinstance(message, dict):
            publish_params['Message'] = json.dumps(message)
        else:
            # If message is already a string, assume it's valid JSON
            publish_params['Message'] = message
        publish_params['MessageStructure'] = 'json'
    else:
        # Default to raw message string
        publish_params['Message'] = message

    if subject:
        publish_params['Subject'] = subject

    response = sns_client.publish(**publish_params)

    return {
        'statusCode': 200,
        'body': json.dumps({
            'messageId': response['MessageId'],
            'status': 'Message published successfully!'
        })
    }